var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>시설 내 인원에게 안내드립니다. 현재, LAKE - 13에서 잔해 격리에 실패했습니다.</color>","JPN":"<color=#ffd34c>施設内の方々にお伝えします。LAKE-13で、残骸の隔離に失敗しました。</color>","ENG":"<color=#ffd34c>Attention, everyone in the facility. Effective immediately, LAKE-13 has failed to quarantine the remains.</color>","TWN":"<color=#ffd34c>設施內的人員請注意，現在播報通知。目前，在LAKE - 13隔離殘骸失敗。</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>대기 중인 병력은 즉시 격리 구역으로 투입해 주시길 바랍니다.</color>","JPN":"<color=#ffd34c>待機中の隊員は、直ちに隔離区域へ向かってください。</color>","ENG":"<color=#ffd34c>All troops on standby must head to the quarantine area immediately.</color>","TWN":"<color=#ffd34c>待命中的兵力請馬上前往隔離區域投入戰鬥。</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>비무장 인원들은</color> <color=#ff3636>격리 구</color><color=#ffd34c>역으로 이동하시어</color> <color=#ff3636>하나가 되</color><color=#ffd34c>길 바랍니다.</color>","JPN":"<color=#ffd34c>非武装者は</color> <color=#ff3636>隔離区域</color><color=#ffd34c>へ移動し、</color> <color=#ff3636>一か所へ集まって</color><color=#ffd34c>ください。</color>","ENG":"<color=#ffd34c>All unarmed personnel should move to the quar</color><color=#ff3636>antine ar</color><color=#ffd34c>ea and beco</color><color=#ff3636>me one imm</color><color=#ffd34c>ediately.</color>","TWN":"<color=#ffd34c>非武裝人員請前往</color><color=#ff3636>隔離區</color><color=#ffd34c>域，</color> <color=#ff3636>合為一體</color><color=#ffd34c>。</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>다시 한 번 안내드립니다. 현재, LAKE-13에서</color> <color=#ff3636>하나가 되겠</color><color=#ffd34c>습니다. 대기 중인 병력은......</color>","JPN":"<color=#ffd34c>もう一度繰り返します。現在、LAKE-13で</color> <color=#ff3636>集まり</color><color=#ffd34c>ます。待機中の隊員は……</color>","ENG":"<color=#ffd34c>Once again. Effective immediately, LAKE-13 has bec</color><color=#ff3636>ome o</color><color=#ffd34c>ne. All troops on standby...</color>","TWN":"<color=#ffd34c>再播報一遍。目前，要在LAKE-13</color><color=#ff3636>合為一體</color><color=#ffd34c>。待命中的兵力……</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"흑...... 흐윽......","JPN":"ぐすん……ぐす……","ENG":"Hngh... Hnnngh...","TWN":"嗚……嗚嗚……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"저기...... 아, 아무도 없어요?","JPN":"あの……だ、誰かいませんか？","ENG":"Is there... a-anyone there?","TWN":"那個……有、有沒有人啊？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"사무장...... 지, 지부장님......!","JPN":"事務長……し、支部長……！","ENG":"Mr. Chief of Staff? B-Branch Manager?","TWN":"事務長……支、支部長……！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"나만...... 남은 거야......?","JPN":"私……一人だけなの……？","ENG":"Am I... the only one left?","TWN":"只剩……我一個人了嗎……？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"잡아먹힐 거야...... 여기 있으면 나도 다른 사람들처럼......","JPN":"食べられちゃう……ここにいれば、他の人たちみたいに……","ENG":"I'll get eaten... like the others, if I stay here...","TWN":"會被吃掉的……待在這裡的話，我也會像其他人一樣……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"무기가 통하지 않아! 어서 아가씨를 패닉 룸으로 모셔!","JPN":"武器が通用しない！　早くお嬢様を、セーフルームへお連れしろ！","ENG":"Our weapons are ineffective! Take her to the panic room!","TWN":"武器沒用！快點帶小姐去避難屋！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"본부에 지원 요청을 보냈어! 요원들이 올 때까지 최대한 시간을 벌어야 한다!","JPN":"本部に援護を要請した！　応援が来るまで、できる限り時間を稼げ！","ENG":"I've asked the HQ for reinforcements! We must buy more time until they get here!","TWN":"已經向總部請求支援了！在特工們到達之前，必須儘量爭取時間！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"어서 가십시오, 아가씨!","JPN":"早く逃げてください、お嬢様！","ENG":"Hurry, my lady!","TWN":"快走吧，小姐！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"......아냐. 무서워도 참아야 돼, 엘리자베스.","JPN":"……ううん。怖くても我慢するのよ、エリザベス。","ENG":"No. You must overcome your fears, Elizabeth.","TWN":"……不，就算害怕也要忍耐，伊莉莎白。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"기관장은 언제나 당당하고 여유로워야 한다고...... 버넷 경이 그랬는걸.","JPN":"首長は、常に穏やかで堂々としているべきだって……バーネット卿が言ってたから。","ENG":"The Chief of the Institution must always be proud and confident... That's what Sir Burnett said.","TWN":"機關長在任何時候都要無所畏懼，自信從容才行……伯內特卿說過的。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};